-- Supabase auth compatibility stubs
-- These replace auth.uid() and auth.jwt() which are Supabase-specific.
-- In our architecture, auth is handled by FastAPI JWT, not by PostgreSQL RLS.
-- These stubs exist only so that exported PL/pgSQL functions can be created without errors.
CREATE SCHEMA IF NOT EXISTS auth;

CREATE OR REPLACE FUNCTION auth.uid() RETURNS uuid AS $$
BEGIN
  -- In FastAPI architecture, auth is handled at the application level.
  -- This stub returns NULL; RPC functions using it should be called
  -- from the backend with explicit user IDs instead.
  RETURN NULL;
END;
$$ LANGUAGE plpgsql STABLE;

CREATE OR REPLACE FUNCTION auth.jwt() RETURNS jsonb AS $$
BEGIN
  RETURN '{}'::jsonb;
END;
$$ LANGUAGE plpgsql STABLE;

-- Functions (RPC)

CREATE OR REPLACE FUNCTION public.activate_subscription_and_reset_limits(p_user_profile_id bigint)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  PERFORM public.assert_own_profile(p_user_profile_id);
  PERFORM public.ensure_limits_row(p_user_profile_id);

  UPDATE public.limits
  SET wardrobe_items_anlyzed = 50,
      wardrobe_items_anlyzed_updated_at = NOW(),
      vton_used = 100,
      vton_used_updated_at = NOW(),
      ai_requests = 20,
      ai_last_reset_at = NOW(),
      ai_requests_updated_at = NOW(),
      monthly_cycle_started_at = NOW(),
      updated_at = NOW()
  WHERE user_profile_id = p_user_profile_id;

  INSERT INTO public.user_credits (user_profile_id, credits_balance, total_earned)
  VALUES (p_user_profile_id, 40, 40)
  ON CONFLICT (user_profile_id) DO UPDATE
  SET credits_balance = public.user_credits.credits_balance + 40,
      total_earned = public.user_credits.total_earned + 40,
      updated_at = NOW();

  INSERT INTO public.credit_transactions(user_profile_id, amount, reason, description)
  VALUES (p_user_profile_id, 40, 'subscription_bonus', '40 credits on subscription activation');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.add_credits(p_user_profile_id integer, p_amount integer, p_reason text, p_description text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  -- upsert баланса
  INSERT INTO public.user_credits (user_profile_id, credits_balance, total_earned)
  VALUES (p_user_profile_id, p_amount, p_amount)
  ON CONFLICT (user_profile_id) DO UPDATE
    SET credits_balance = public.user_credits.credits_balance + EXCLUDED.credits_balance,
        total_earned    = public.user_credits.total_earned    + EXCLUDED.total_earned,
        updated_at      = NOW();

  -- лог транзакции: ТИП ДОЛЖЕН БЫТЬ 'credit'
  INSERT INTO public.credit_transactions (
    user_profile_id, transaction_type, amount, description, feature_used, created_at
  ) VALUES (
    p_user_profile_id, 'credit', p_amount, p_description, p_reason, NOW()
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.add_user_credits(credits_to_add integer, description text, target_user_id uuid, transaction_type text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_user_profile_id INTEGER;
    v_is_admin BOOLEAN := FALSE;
BEGIN
    -- Проверка прав (кто вызывает — админ)
    SELECT COALESCE(is_admin, FALSE)
      INTO v_is_admin
      FROM public.user_profiles
     WHERE user_id = auth.uid();

    IF NOT v_is_admin THEN
        RAISE EXCEPTION 'Access denied: Only admins can add credits to users';
    END IF;

    -- Получаем числовой profile.id целевого пользователя
    SELECT id
      INTO STRICT v_user_profile_id
      FROM public.user_profiles
     WHERE user_id = target_user_id;

    -- Upsert баланса (основание — уникальный индекс на user_profile_id)
    INSERT INTO public.user_credits AS uc
        (user_profile_id, credits_balance, total_earned, created_at, updated_at)
    VALUES
        (v_user_profile_id, credits_to_add, credits_to_add, NOW(), NOW())
    ON CONFLICT (user_profile_id) DO UPDATE
       SET credits_balance = uc.credits_balance + EXCLUDED.credits_balance,
           total_earned    = uc.total_earned    + EXCLUDED.total_earned,
           updated_at      = NOW();

    -- Лог транзакции (тип приводим к допустимому по CHECK, например 'credit')
    INSERT INTO public.credit_transactions
        (user_profile_id, transaction_type, amount, description, feature_used, created_at)
    VALUES
        (v_user_profile_id, 'credit', credits_to_add, description, 'admin_grant', NOW());

    RETURN TRUE;

EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'Failed to add credits: %', SQLERRM;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.assert_own_profile(p_user_profile_id bigint)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  -- 1) Разрешаем сервисным ключам
  IF coalesce(auth.jwt() ->> 'role', '') = 'service_role' THEN
    RETURN;
  END IF;

  -- 2) Разрешаем текущим админам (по вашей функции is_current_user_admin)
  IF public.is_current_user_admin() THEN
    RETURN;
  END IF;

  -- 3) Обычная проверка «сам за себя»
  IF NOT EXISTS (
    SELECT 1
    FROM public.user_profiles up
    WHERE up.id = p_user_profile_id
      AND up.user_id = auth.uid()
  ) THEN
    RAISE EXCEPTION 'forbidden: profile mismatch';
  END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.can_use_feature(p_user_profile_id bigint, p_feature character varying, p_count integer DEFAULT 1)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  l public.limits;
  bal INTEGER := 0;
  need_units INTEGER := 0;
  cost_per_unit INTEGER := 0;
  grant_per_unit INTEGER := 1;
BEGIN
  PERFORM public.assert_own_profile(p_user_profile_id);
  PERFORM public.reconcile_limits(p_user_profile_id);

  SELECT * INTO l FROM public.limits WHERE user_profile_id = p_user_profile_id;

  IF p_feature = 'wardrobe_items_anlyzed' THEN
    IF l.wardrobe_items_anlyzed >= p_count THEN RETURN TRUE; END IF;
    need_units := p_count - l.wardrobe_items_anlyzed; cost_per_unit := 5; grant_per_unit := 1;
  ELSIF p_feature = 'ai_requests' THEN
    IF l.ai_requests >= p_count THEN RETURN TRUE; END IF;
    need_units := p_count - l.ai_requests; cost_per_unit := 2; grant_per_unit := 5;
  ELSIF p_feature = 'vton_used' THEN
    IF l.vton_used >= p_count THEN RETURN TRUE; END IF;
    need_units := p_count - l.vton_used; cost_per_unit := 3; grant_per_unit := 1;
  ELSIF p_feature = 'ideas_viewed' THEN
    RETURN l.ideas_viewed >= p_count;
  ELSIF p_feature = 'outfits_saved' THEN
    RETURN l.outfits_saved >= p_count;
  ELSE
    RETURN FALSE;
  END IF;

  SELECT credits_balance INTO bal FROM public.user_credits WHERE user_profile_id = p_user_profile_id;
  IF bal IS NULL THEN bal := 0; END IF;

  RETURN bal >= CEIL(need_units::NUMERIC / grant_per_unit) * cost_per_unit;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_daily_limit(p_user_id uuid, p_usage_type character varying, p_increment integer DEFAULT 1)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
  current_usage INTEGER := 0;
  daily_limit INTEGER := 0;
  has_subscription BOOLEAN := FALSE;
BEGIN
  -- Check if user has active subscription
  SELECT EXISTS(
    SELECT 1 FROM user_subscriptions 
    WHERE user_id = p_user_id 
    AND status = 'active' 
    AND expires_at > NOW()
  ) INTO has_subscription;
  
  -- Get current daily usage
  SELECT 
    CASE 
      WHEN p_usage_type = 'wardrobe_digitizations' THEN COALESCE(wardrobe_digitizations, 0)
      WHEN p_usage_type = 'ai_requests' THEN COALESCE(ai_requests, 0)
      WHEN p_usage_type = 'ideas_views' THEN COALESCE(ideas_views, 0)
      WHEN p_usage_type = 'outfits_saved' THEN COALESCE(outfits_saved, 0)
      ELSE 0
    END
  INTO current_usage
  FROM daily_usage 
  WHERE user_id = p_user_id AND usage_date = CURRENT_DATE;
  
  -- Set limits based on subscription status
  CASE p_usage_type
    WHEN 'wardrobe_digitizations' THEN daily_limit := 5;
    WHEN 'ai_requests' THEN daily_limit := CASE WHEN has_subscription THEN 20 ELSE 1 END;
    WHEN 'ideas_views' THEN daily_limit := 10;
    WHEN 'outfits_saved' THEN daily_limit := 999; -- No daily limit, only total limit
    ELSE daily_limit := 0;
  END CASE;
  
  -- Check if limit would be exceeded
  IF current_usage + p_increment > daily_limit THEN
    RETURN FALSE;
  END IF;
  
  -- Update usage
  INSERT INTO daily_usage (user_id, usage_date, wardrobe_digitizations, ai_requests, ideas_views, outfits_saved)
  VALUES (
    p_user_id, 
    CURRENT_DATE,
    CASE WHEN p_usage_type = 'wardrobe_digitizations' THEN p_increment ELSE 0 END,
    CASE WHEN p_usage_type = 'ai_requests' THEN p_increment ELSE 0 END,
    CASE WHEN p_usage_type = 'ideas_views' THEN p_increment ELSE 0 END,
    CASE WHEN p_usage_type = 'outfits_saved' THEN p_increment ELSE 0 END
  )
  ON CONFLICT (user_id, usage_date) DO UPDATE SET
    wardrobe_digitizations = daily_usage.wardrobe_digitizations + 
      CASE WHEN p_usage_type = 'wardrobe_digitizations' THEN p_increment ELSE 0 END,
    ai_requests = daily_usage.ai_requests + 
      CASE WHEN p_usage_type = 'ai_requests' THEN p_increment ELSE 0 END,
    ideas_views = daily_usage.ideas_views + 
      CASE WHEN p_usage_type = 'ideas_views' THEN p_increment ELSE 0 END,
    outfits_saved = daily_usage.outfits_saved + 
      CASE WHEN p_usage_type = 'outfits_saved' THEN p_increment ELSE 0 END,
    updated_at = NOW();
    
  RETURN TRUE;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_total_limit(p_user_id uuid, p_limit_type character varying)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
  current_count INTEGER := 0;
  total_limit INTEGER := 0;
BEGIN
  -- Get current totals
  SELECT 
    CASE 
      WHEN p_limit_type = 'wardrobe_items' THEN COALESCE(total_wardrobe_items, 0)
      WHEN p_limit_type = 'saved_outfits' THEN COALESCE(total_saved_outfits, 0)
      ELSE 0
    END
  INTO current_count
  FROM user_limits 
  WHERE user_id = p_user_id;
  
  -- Set total limits
  CASE p_limit_type
    WHEN 'wardrobe_items' THEN total_limit := 20;
    WHEN 'saved_outfits' THEN total_limit := 20;
    ELSE total_limit := 0;
  END CASE;
  
  RETURN current_count < total_limit;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.enqueue_recs_jobs()
 RETURNS void
 LANGUAGE sql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
  insert into public.recs_jobs (user_id, run_date, status)
  select au.user_id, current_date, 'queued'
  from public.active_users_for_recs au
  on conflict (user_id, run_date) do nothing;
$function$
;

CREATE OR REPLACE FUNCTION public.ensure_limits_row(p_user_profile_id bigint)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  PERFORM public.assert_own_profile(p_user_profile_id);

  INSERT INTO public.limits (user_profile_id)
  VALUES (p_user_profile_id)
  ON CONFLICT (user_profile_id) DO NOTHING;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.ensure_single_primary_avatar()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- If setting this avatar as primary, unset all other primary avatars for this user
  IF NEW.is_primary = true THEN
    UPDATE user_avatars 
    SET is_primary = false 
    WHERE user_id = NEW.user_id AND id != NEW.id;
  END IF;
  
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.exec_sql(sql text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  EXECUTE sql;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.find_pattern_counts(pattern text)
 RETURNS TABLE(table_schema text, table_name text, column_name text, match_count bigint)
 LANGUAGE plpgsql
AS $function$
DECLARE
  r record;
  v_sql text;
BEGIN
  FOR r IN
    WITH text_cols AS (
      SELECT 
        cols.table_schema,
        cols.table_name,
        cols.column_name
      FROM information_schema.columns cols
      JOIN information_schema.tables t
        ON t.table_schema = cols.table_schema
       AND t.table_name = cols.table_name
      WHERE t.table_type = 'BASE TABLE'
        AND cols.table_schema NOT IN ('pg_catalog', 'information_schema')
        AND cols.data_type IN ('text', 'character varying', 'character')
    )
    SELECT * FROM text_cols
  LOOP
    v_sql := format(
      'SELECT count(*) FROM %I.%I WHERE %I ILIKE %L',
      r.table_schema, r.table_name, r.column_name, pattern
    );
    RETURN QUERY EXECUTE
      format('SELECT %L::text, %L::text, %L::text, (%s)::bigint',
             r.table_schema, r.table_name, r.column_name, v_sql);
  END LOOP;
END $function$
;

CREATE OR REPLACE FUNCTION public.generate_and_store_recs_for_user(p_user_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth', 'extensions'
AS $function$
declare
  v_url       text;
  v_status    int;
  v_content   text;
  v_gender    text;
  v_weather   jsonb;
  v_payload   text;
begin
  -- HTTP таймаут для этой функции (в миллисекундах)
  perform set_config('http.timeout_msec', '180000', true);  -- 3 минуты

  select value into v_url
  from public.recs_settings
  where key = 'recs_endpoint_url';
  if v_url is null then
    raise exception using message = 'recs_endpoint_url is not set in recs_settings';
  end if;

  select up.gender into v_gender
  from public.user_profiles up
  where up.user_id = p_user_id;

  v_weather := public.get_weather_for_user(p_user_id);

  v_payload := jsonb_build_object(
    'user_id', p_user_id,
    'gender',  v_gender,
    'weather', v_weather
  )::text;

  -- http_post(url, body, content_type) -> (status, content_type, headers, content)
  select r.status, r.content
    into v_status, v_content
  from extensions.http_post(
         v_url,
         v_payload,
         'application/json'
       ) as r;

  if v_status != 200 then
    raise exception using
      message = 'Recommendation endpoint returned non-200',
      detail  = format('url=%s status=%s user_id=%s', v_url, v_status, p_user_id);
  end if;

  perform public.save_user_main_recommendation(
    p_user_id,
    v_content::jsonb,
    'algo:http'
  );
end;
$function$
;

CREATE OR REPLACE FUNCTION public.get_feature_cost(p_user_profile_id integer, p_feature_name character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  has_subscription BOOLEAN := FALSE;
  regular_cost INTEGER := 0;
  subscription_cost INTEGER := 0;
BEGIN
  -- Check if user has active subscription
  SELECT EXISTS(
    SELECT 1 FROM user_subscriptions 
    WHERE user_profile_id = p_user_profile_id 
    AND status = 'active' 
    AND expires_at > NOW()
  ) INTO has_subscription;
  
  -- Get costs for the feature
  SELECT cost_credits, cost_subscription_credits
  INTO regular_cost, subscription_cost
  FROM feature_costs 
  WHERE feature_name = p_feature_name AND is_active = true;
  
  -- Return appropriate cost based on subscription status
  IF has_subscription THEN
    RETURN subscription_cost;
  ELSE
    RETURN regular_cost;
  END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_feature_cost(p_user_profile_id integer, p_feature_key text)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  has_sub boolean := false;
  v_cost  integer := 0;
BEGIN
  -- активная подписка "на сейчас"
  SELECT EXISTS (
    SELECT 1
      FROM public.user_subscriptions
     WHERE user_profile_id = p_user_profile_id
       AND status = 'active'
       AND start_date <= NOW()
       AND (expires_at IS NULL OR expires_at >= NOW())
  ) INTO has_sub;

  -- стоимость из feature_costs
  SELECT CASE
           WHEN has_sub THEN COALESCE(cost_subscription_credits, cost_credits)
           ELSE COALESCE(cost_credits, 0)
         END
    INTO v_cost
    FROM public.feature_costs
   WHERE feature_name = p_feature_key
     AND is_active = TRUE
   LIMIT 1;

  RETURN COALESCE(v_cost, 0);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_user_profile_id(user_uuid uuid)
 RETURNS bigint
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
    RETURN (SELECT id FROM user_profiles WHERE user_id = user_uuid LIMIT 1);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_user_subscription_status(user_profile_id_param bigint)
 RETURNS TABLE(subscription_type character varying, status character varying, start_date timestamp with time zone, end_date timestamp with time zone, credits_included integer, is_active boolean)
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN QUERY
  SELECT 
    us.subscription_type,
    us.status,
    us.start_date,
    us.end_date,
    us.credits_included,
    (us.status = 'active' AND us.end_date > NOW()) as is_active
  FROM user_subscriptions us
  WHERE us.user_profile_id = user_profile_id_param
  ORDER BY us.created_at DESC
  LIMIT 1;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_weather_for_user(p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
declare
  v_row record;
  v_default_temp integer;
  v_default_condition text;
  v_month integer;
begin
  -- Получаем данные пользователя
  select
    wc.city_name,
    wc.temperature,
    wc.condition,
    wc.description,
    wc.humidity,
    wc.wind_speed,
    wc.latitude,
    wc.longitude,
    wc.updated_at
  into v_row
  from public.weather_cache wc
  where wc.user_id = p_user_id;

  -- Если данные есть и они свежие (меньше 24 часов) — возвращаем их
  if found and v_row.temperature is not null
     and v_row.updated_at > now() - interval '24 hours' then
    return jsonb_build_object(
      'city_name',   v_row.city_name,
      'temperature', v_row.temperature,
      'condition',   v_row.condition,
      'description', v_row.description,
      'humidity',    v_row.humidity,
      'wind_speed',  v_row.wind_speed,
      'latitude',    v_row.latitude,
      'longitude',   v_row.longitude,
      'updated_at',  to_char(v_row.updated_at, 'YYYY-MM-DD"T"HH24:MI:SS.MS"Z"'),
      'user_id',     p_user_id
    );
  end if;

  -- Дефолтная погода для Москвы по сезону
  v_month := extract(month from now());

  -- Примерные средние температуры для Москвы по месяцам
  case v_month
    when 1 then v_default_temp := -8; v_default_condition := 'Snow';
    when 2 then v_default_temp := -6; v_default_condition := 'Snow';
    when 3 then v_default_temp := 0; v_default_condition := 'Clouds';
    when 4 then v_default_temp := 8; v_default_condition := 'Clouds';
    when 5 then v_default_temp := 15; v_default_condition := 'Clouds';
    when 6 then v_default_temp := 20; v_default_condition := 'Clear';
    when 7 then v_default_temp := 23; v_default_condition := 'Clear';
    when 8 then v_default_temp := 21; v_default_condition := 'Clouds';
    when 9 then v_default_temp := 14; v_default_condition := 'Clouds';
    when 10 then v_default_temp := 7; v_default_condition := 'Rain';
    when 11 then v_default_temp := 1; v_default_condition := 'Clouds';
    when 12 then v_default_temp := -5; v_default_condition := 'Snow';
    else v_default_temp := 10; v_default_condition := 'Clouds';
  end case;

  -- Возвращаем дефолт для Москвы
  return jsonb_build_object(
    'city_name',   'Москва',
    'temperature', v_default_temp,
    'condition',   v_default_condition,
    'description', 'default weather for Moscow',
    'humidity',    70,
    'wind_speed',  3,
    'latitude',    55.7558,
    'longitude',   37.6176,
    'updated_at',  to_char(now(), 'YYYY-MM-DD"T"HH24:MI:SS.MS"Z"'),
    'user_id',     p_user_id,
    'is_default',  true
  );
end;
$function$
;

CREATE OR REPLACE FUNCTION public.handle_new_user()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  tg_first  text := nullif(new.raw_user_meta_data->>'telegram_first_name','');
  tg_last   text := nullif(new.raw_user_meta_data->>'telegram_last_name','');
  tg_user   text := nullif(new.raw_user_meta_data->>'telegram_username','');
  tg_full   text := nullif(new.raw_user_meta_data->>'full_name','');
  photo_url text := nullif(new.raw_user_meta_data->>'telegram_photo_url','');
  full_name text := null;
begin
  -- Формируем удобочитаемое имя: "Имя Фамилия" → full_name (если есть), иначе username
  full_name := coalesce(
    nullif(trim(coalesce(tg_first,'') || ' ' || coalesce(tg_last,'')),''),
    tg_full,
    tg_user,
    'User'
  );

  insert into public.user_profiles (user_id, is_admin, full_name, avatar_url, created_at, updated_at)
  values (new.id, false, full_name, photo_url, now(), now())
  on conflict (user_id) do update
    set is_admin   = false,                    -- не даём телеграм-аккаунтам стать админом автоматически
        full_name  = excluded.full_name,       -- обновляем имя по последним данным
        avatar_url = excluded.avatar_url,
        updated_at = now();

  return new;

exception
  when others then
    perform pg_notify('handle_new_user_error', sqlerrm);
    return new;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.handle_new_user_profile()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
begin
  if not new.is_admin then
    begin
      perform initialize_user_credits(new.id); -- если есть; иначе просто проглатываем
    exception
      when others then
        perform pg_notify('handle_new_user_profile_error', sqlerrm);
        -- не прерываем транзакцию
    end;
  end if;
  return new;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.has_purchased_credits(p_user_profile_id bigint)
 RETURNS boolean
 LANGUAGE sql
 STABLE
AS $function$
  SELECT EXISTS (
    SELECT 1 FROM public.credit_transactions ct
    WHERE ct.user_profile_id = p_user_profile_id
      AND ct.amount > 0
      AND ct.reason = 'purchase_pack'  -- важно: не считаем subscription_bonus
  );
$function$
;

