 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  UPDATE outfits 
  SET views_count = COALESCE(views_count, 0) + 1
  WHERE id = outfit_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.init_limits_for_user(p_user_profile_id bigint)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  PERFORM public.assert_own_profile(p_user_profile_id);
  PERFORM public.ensure_limits_row(p_user_profile_id);

  UPDATE public.limits SET
    wardrobe_items_anlyzed = 10,
    wardrobe_items_anlyzed_updated_at = NOW(),
    vton_used = 5,
    vton_used_updated_at = NOW(),
    ai_requests = 3,
    ai_last_reset_at = NOW(),
    ai_requests_updated_at = NOW(),
    ideas_viewed = 9999,
    outfits_saved = 9999,
    ideas_viewed_updated_at = NOW(),
    outfits_saved_updated_at = NOW(),
    ideas_outfits_last_reset_at = NOW(),
    monthly_cycle_started_at = NULL,
    updated_at = NOW()
  WHERE user_profile_id = p_user_profile_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.initialize_user_credits(user_profile_id bigint)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  INSERT INTO public.user_credits (user_profile_id, credits_balance, total_earned)
  VALUES (user_profile_id, 30, 30)
  ON CONFLICT (user_profile_id) DO NOTHING;

  INSERT INTO public.user_limits (user_profile_id)
  VALUES (user_profile_id)
  ON CONFLICT (user_profile_id) DO NOTHING;

  -- лог "welcome_bonus" один раз
  IF NOT EXISTS (
    SELECT 1 FROM public.credit_transactions
    WHERE user_profile_id = user_profile_id
      AND reason = 'welcome_bonus'
  ) THEN
    INSERT INTO public.credit_transactions
      (user_profile_id, transaction_type, amount, reason, description)
    VALUES
      (user_profile_id, 'earn', 30, 'welcome_bonus', 'Приветственный бонус для нового пользователя');
  END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.is_current_user_admin()
 RETURNS boolean
 LANGUAGE sql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
  select exists (
    select 1
    from public.user_profiles up
    where up.user_id = auth.uid()
      and coalesce(up.is_admin, false) = true
  );
$function$
;

CREATE OR REPLACE FUNCTION public.is_subscriber(p_user_profile_id bigint)
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  ok BOOLEAN;
BEGIN
  SELECT EXISTS(
    SELECT 1 FROM public.user_subscriptions us
    WHERE us.user_profile_id = p_user_profile_id
      AND us.status = 'active'
      AND COALESCE(us.expires_at, NOW() + interval '1 hour') > NOW()
  ) INTO ok;
  RETURN ok;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.is_user_admin(user_uuid uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  RETURN EXISTS (
    SELECT 1 FROM user_profiles 
    WHERE user_id = user_uuid AND is_admin = true
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.log_usage_event(p_user_profile_id bigint, p_feature character varying, p_action character varying, p_count integer DEFAULT 1, p_page_path text DEFAULT NULL::text, p_item_id bigint DEFAULT NULL::bigint, p_request_id uuid DEFAULT NULL::uuid, p_metadata jsonb DEFAULT '{}'::jsonb)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  sub BOOLEAN;
  bought BOOLEAN;
  bal INTEGER;
  l RECORD;
  anon TEXT;
BEGIN
  -- проверка «это мой профиль»
  PERFORM public.assert_own_profile(p_user_profile_id);

  -- вычисляем флаги
  sub := public.is_subscriber(p_user_profile_id);
  bought := public.has_purchased_credits(p_user_profile_id);

  SELECT credits_balance INTO bal
  FROM public.user_credits
  WHERE user_profile_id = p_user_profile_id;

  SELECT
    wardrobe_items_anlyzed,
    ai_requests,
    ideas_viewed,
    outfits_saved,
    vton_used
  INTO l
  FROM public.limits
  WHERE user_profile_id = p_user_profile_id;

  anon := public.user_anon_hash(p_user_profile_id);

  INSERT INTO public.usage_events(
    user_profile_id, user_anon_id, feature, action, count,
    is_subscriber, has_bought_credits, credits_balance, limits_snapshot,
    page_path, item_id, request_id, metadata
  ) VALUES (
    p_user_profile_id, anon, p_feature, p_action, GREATEST(1, COALESCE(p_count,1)),
    COALESCE(sub,false), COALESCE(bought,false), bal,
    to_jsonb(l),
    p_page_path, p_item_id, p_request_id, COALESCE(p_metadata, '{}'::jsonb)
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.purchase_feature_usage(p_user_profile_id integer, p_feature_type character varying)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
  feature_name VARCHAR(50);
  reg_cost INTEGER;
  sub_cost INTEGER;
  usage_inc INTEGER;
  has_sub BOOLEAN;
  success BOOLEAN := TRUE;
BEGIN
  -- сопоставляем внутренний тип с именем в feature_costs
  feature_name := CASE
    WHEN p_feature_type = 'wardrobe_items' THEN 'wardrobe_digitization'
    WHEN p_feature_type = 'ai_requests' THEN 'ai_assistant'
    WHEN p_feature_type = 'ideas_viewed' THEN 'ideas_viewing'
    WHEN p_feature_type = 'outfits_saved' THEN 'outfit_creation'
    ELSE p_feature_type
  END;

  -- проверяем подписку
  SELECT EXISTS (
    SELECT 1 FROM user_subscriptions
    WHERE user_profile_id = p_user_profile_id
      AND status = 'active'
      AND expires_at > NOW()
  ) INTO has_sub;

  -- читаем стоимость и количество бонусных использований
  SELECT cost_credits, cost_subscription_credits, usage_increment
    INTO reg_cost, sub_cost, usage_inc
    FROM feature_costs
    WHERE feature_name = feature_name AND is_active = TRUE;

  IF usage_inc IS NULL THEN
    RETURN FALSE;
  END IF;

  IF has_sub THEN
    IF sub_cost > 0 THEN
      SELECT spend_credits(p_user_profile_id, sub_cost, feature_name, 'Оплата за использование функции')
        INTO success;
    END IF;
  ELSE
    IF reg_cost > 0 THEN
      SELECT spend_credits(p_user_profile_id, reg_cost, feature_name, 'Оплата за использование функции')
        INTO success;
    END IF;
  END IF;

  IF NOT success THEN
    RETURN FALSE;
  END IF;

  -- увеличиваем бонусный счётчик
  IF p_feature_type = 'wardrobe_items' THEN
    UPDATE daily_usage_limits
      SET wardrobe_items_bonus_today = wardrobe_items_bonus_today + usage_inc,
          updated_at = NOW()
      WHERE user_profile_id = p_user_profile_id;
  ELSIF p_feature_type = 'ai_requests' THEN
    UPDATE daily_usage_limits
      SET ai_requests_bonus_today = ai_requests_bonus_today + usage_inc,
          updated_at = NOW()
      WHERE user_profile_id = p_user_profile_id;
  ELSIF p_feature_type = 'ideas_viewed' THEN
    UPDATE daily_usage_limits
      SET ideas_viewed_bonus_today = ideas_viewed_bonus_today + usage_inc,
          updated_at = NOW()
      WHERE user_profile_id = p_user_profile_id;
  ELSIF p_feature_type = 'outfits_saved' THEN
    UPDATE daily_usage_limits
      SET outfits_saved_bonus_today = outfits_saved_bonus_today + usage_inc,
          updated_at = NOW()
      WHERE user_profile_id = p_user_profile_id;
  END IF;

  RETURN TRUE;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.reconcile_limits(p_user_profile_id bigint)
 RETURNS limits
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  l public.limits;
  has_sub BOOLEAN;
  target_daily_ai INTEGER := 3;
  now_ts TIMESTAMPTZ := NOW();
BEGIN
  PERFORM public.assert_own_profile(p_user_profile_id);
  PERFORM public.ensure_limits_row(p_user_profile_id);

  SELECT public.is_subscriber(p_user_profile_id) INTO has_sub;

  IF has_sub THEN
    target_daily_ai := 20;

    SELECT * INTO l FROM public.limits WHERE user_profile_id = p_user_profile_id FOR UPDATE;
    IF l.monthly_cycle_started_at IS NULL
       OR (now_ts >= l.monthly_cycle_started_at + interval '1 month') THEN
      UPDATE public.limits
      SET wardrobe_items_anlyzed = 50,
          wardrobe_items_anlyzed_updated_at = now_ts,
          vton_used = 100,
          vton_used_updated_at = now_ts,
          monthly_cycle_started_at = COALESCE(l.monthly_cycle_started_at, now_ts),
          updated_at = now_ts
      WHERE user_profile_id = p_user_profile_id;
    END IF;
  END IF;

  -- daily ai reset (по смене календарной даты)
  SELECT * INTO l FROM public.limits WHERE user_profile_id = p_user_profile_id FOR UPDATE;
  IF l.ai_last_reset_at IS NULL
     OR (CURRENT_DATE > (l.ai_last_reset_at AT TIME ZONE 'UTC')::date) THEN
    UPDATE public.limits
    SET ai_requests = target_daily_ai,
        ai_last_reset_at = now_ts,
        ai_requests_updated_at = now_ts,
        updated_at = now_ts
    WHERE user_profile_id = p_user_profile_id;
  END IF;

  -- monthly ideas/outfits
  SELECT * INTO l FROM public.limits WHERE user_profile_id = p_user_profile_id FOR UPDATE;
  IF l.ideas_outfits_last_reset_at IS NULL
     OR (now_ts >= l.ideas_outfits_last_reset_at + interval '1 month') THEN
    UPDATE public.limits
    SET ideas_viewed = 9999,
        outfits_saved = 9999,
        ideas_viewed_updated_at = now_ts,
        outfits_saved_updated_at = now_ts,
        ideas_outfits_last_reset_at = now_ts,
        updated_at = now_ts
    WHERE user_profile_id = p_user_profile_id;
  END IF;

  SELECT * INTO l FROM public.limits WHERE user_profile_id = p_user_profile_id;
  RETURN l;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.record_user_activity(p_user_profile_id bigint)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_today DATE := CURRENT_DATE;
BEGIN
    INSERT INTO daily_user_activity (
        user_profile_id,
        activity_date,
        first_seen_at,
        last_seen_at,
        activity_count
    ) VALUES (
        p_user_profile_id,
        v_today,
        NOW(),
        NOW(),
        1
    )
    ON CONFLICT (user_profile_id, activity_date)
    DO UPDATE SET
        last_seen_at = NOW(),
        activity_count = daily_user_activity.activity_count + 1,
        updated_at = NOW();
END;
$function$
;

CREATE OR REPLACE FUNCTION public.refresh_weather_for_user(p_user_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth', 'extensions'
AS $function$
declare
  v_lat numeric; v_lon numeric;
  v_key text; v_url text;
  v_status int; v_content text; v_json jsonb;
begin
  -- координаты строго из weather_cache
  select latitude, longitude
    into v_lat, v_lon
  from public.weather_cache
  where user_id = p_user_id;

  if v_lat is null or v_lon is null then
    return false; -- нет координат — не обновляем
  end if;

  select value into v_key
  from public.recs_settings
  where key = 'weather_api_key';
  if v_key is null then
    return false; -- нет ключа — тихо уходим
  end if;

  -- таймаут на HTTP (в миллисекундах)
  perform set_config('http.timeout_msec', '12000', true); -- 12s

  -- лёгкий джиттер, чтобы не бить ровно одновременно
  perform pg_sleep(0.1 + random() * 0.3);

  v_url := format(
    'https://api.openweathermap.org/data/2.5/weather?lat=%s&lon=%s&appid=%s&units=metric&lang=ru',
    v_lat, v_lon, v_key
  );

  -- http_get(url) -> (status, content_type, headers, content)
  begin
    select r.status, r.content
      into v_status, v_content
    from extensions.http_get(v_url) as r;
  exception when others then
    return false;
  end;

  if v_status != 200 then
    return false;
  end if;

  v_json := v_content::jsonb;

  -- апдейт полей кэша
  update public.weather_cache
     set city_name   = nullif(v_json #>> '{name}', ''),
         temperature = (v_json #>> '{main,temp}')::numeric,
         condition   = v_json #>> '{weather,0,main}',
         description = v_json #>> '{weather,0,description}',
         humidity    = (v_json #>> '{main,humidity}')::numeric,
         wind_speed  = (v_json #>> '{wind,speed}')::numeric,
         updated_at  = now()
   where user_id = p_user_id;

  return true;
end;
$function$
;

