CREATE OR REPLACE FUNCTION public.spend_credits(p_user_profile_id integer, p_amount integer, p_reason text, p_description text DEFAULT NULL::text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_balance  integer;
  v_reason   text := lower(coalesce(p_reason,''));
  v_units    integer := 0;
BEGIN
  -- доступ только владельцу профиля
  PERFORM 1 FROM public.user_profiles
   WHERE id = p_user_profile_id AND user_id = auth.uid();
  IF NOT FOUND THEN RAISE EXCEPTION 'Forbidden'; END IF;

  -- нормализация
  v_reason := CASE
                WHEN v_reason IN ('ideas_viewing','ideas_views','ideas_viewed','ideas') THEN 'ideas_views'
                WHEN v_reason IN ('ai_assistant','ai_requests','ai')                     THEN 'ai_requests'
                WHEN v_reason IN ('wardrobe_digitization','wardrobe_digitizations','digitize','wardrobe_items')
                                                                                         THEN 'wardrobe_items'
                WHEN v_reason IN ('outfits_saved','outfit_creation')                     THEN 'outfits_saved'
                WHEN v_reason IN ('ai_try_on','try_on','tryon')                          THEN 'ai_try_on'
                ELSE v_reason
              END;

  -- инициализация баланса
  INSERT INTO public.user_credits (user_profile_id, credits_balance, total_earned, total_spent, created_at, updated_at)
  VALUES (p_user_profile_id, 0, 0, 0, NOW(), NOW())
  ON CONFLICT (user_profile_id) DO NOTHING;

  -- блокировка / проверка средств
  SELECT credits_balance INTO v_balance
    FROM public.user_credits
   WHERE user_profile_id = p_user_profile_id
   FOR UPDATE;
  IF p_amount IS NULL OR p_amount <= 0 OR v_balance IS NULL OR v_balance < p_amount THEN
    RETURN FALSE;
  END IF;

  -- списание
  UPDATE public.user_credits
     SET credits_balance = credits_balance - p_amount,
         total_spent     = COALESCE(total_spent,0) + p_amount,
         updated_at      = NOW()
   WHERE user_profile_id = p_user_profile_id;

  INSERT INTO public.credit_transactions
      (user_profile_id, transaction_type, amount, description, feature_used, created_at)
  VALUES (p_user_profile_id, 'spend', p_amount, p_description, v_reason, NOW());

  -- подготовка daily_usage_limits + мягкий сброс
  INSERT INTO public.daily_usage_limits
    (user_profile_id, wardrobe_items_today, ai_requests_today, ideas_viewed_today, outfits_saved_today,
     wardrobe_items_bonus_today, ai_requests_bonus_today, ideas_viewed_bonus_today, outfits_saved_bonus_today,
     last_reset_date, created_at, updated_at)
  VALUES (p_user_profile_id, 0, 0, 0, 0, 0, 0, 0, 0, CURRENT_DATE, NOW(), NOW())
  ON CONFLICT (user_profile_id) DO UPDATE
  SET wardrobe_items_today = CASE WHEN daily_usage_limits.last_reset_date < CURRENT_DATE THEN 0 ELSE daily_usage_limits.wardrobe_items_today END,
      ai_requests_today    = CASE WHEN daily_usage_limits.last_reset_date < CURRENT_DATE THEN 0 ELSE daily_usage_limits.ai_requests_today    END,
      ideas_viewed_today   = CASE WHEN daily_usage_limits.last_reset_date < CURRENT_DATE THEN 0 ELSE daily_usage_limits.ideas_viewed_today   END,
      outfits_saved_today  = CASE WHEN daily_usage_limits.last_reset_date < CURRENT_DATE THEN 0 ELSE daily_usage_limits.outfits_saved_today  END,
      wardrobe_items_bonus_today = CASE WHEN daily_usage_limits.last_reset_date < CURRENT_DATE THEN 0 ELSE daily_usage_limits.wardrobe_items_bonus_today END,
      ai_requests_bonus_today    = CASE WHEN daily_usage_limits.last_reset_date < CURRENT_DATE THEN 0 ELSE daily_usage_limits.ai_requests_bonus_today    END,
      ideas_viewed_bonus_today   = CASE WHEN daily_usage_limits.last_reset_date < CURRENT_DATE THEN 0 ELSE daily_usage_limits.ideas_viewed_bonus_today   END,
      outfits_saved_bonus_today  = CASE WHEN daily_usage_limits.last_reset_date < CURRENT_DATE THEN 0 ELSE daily_usage_limits.outfits_saved_bonus_today  END,
      last_reset_date = CASE WHEN daily_usage_limits.last_reset_date < CURRENT_DATE THEN CURRENT_DATE ELSE daily_usage_limits.last_reset_date END,
      updated_at = NOW();

  -- покупка бонусов
  IF v_reason = 'ideas_views' THEN
    v_units := GREATEST(FLOOR(p_amount / 2), 0);       -- 2 токена => +5 просмотров
    IF v_units >= 1 THEN
      UPDATE public.daily_usage_limits
         SET ideas_viewed_bonus_today = ideas_viewed_bonus_today + (5 * v_units),
             updated_at = NOW()
       WHERE user_profile_id = p_user_profile_id;
    END IF;

  ELSIF v_reason = 'ai_requests' THEN
    v_units := GREATEST(FLOOR(p_amount / 2), 0);       -- 2 токена => +1 запрос
    IF v_units >= 1 THEN
      UPDATE public.daily_usage_limits
         SET ai_requests_bonus_today = ai_requests_bonus_today + v_units,
             updated_at = NOW()
       WHERE user_profile_id = p_user_profile_id;
    END IF;

  ELSIF v_reason = 'wardrobe_items' THEN
    v_units := GREATEST(FLOOR(p_amount / 5), 0);       -- 5 токенов => +1 оцифровка
    IF v_units >= 1 THEN
      UPDATE public.daily_usage_limits
         SET wardrobe_items_bonus_today = wardrobe_items_bonus_today + v_units,
             updated_at = NOW()
       WHERE user_profile_id = p_user_profile_id;
    END IF;
  END IF;

  RETURN TRUE;
EXCEPTION
  WHEN OTHERS THEN
    RAISE EXCEPTION 'Failed to spend credits: %', SQLERRM;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.tg_set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin
  new.updated_at := now();
  return new;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.top_up_from_credits(p_user_profile_id bigint, p_feature text, p_need_units integer)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  cost_per_unit INTEGER;
  grant_per_unit INTEGER;
  packs_needed INTEGER;
  bal INTEGER;
BEGIN
  PERFORM public.assert_own_profile(p_user_profile_id);

  IF p_feature = 'wardrobe_items_anlyzed' THEN
    cost_per_unit := 5; grant_per_unit := 1;
  ELSIF p_feature = 'ai_requests' THEN
    cost_per_unit := 2; grant_per_unit := 5;
  ELSIF p_feature = 'vton_used' THEN
    cost_per_unit := 3; grant_per_unit := 1;
  ELSE
    RETURN FALSE;
  END IF;

  packs_needed := CEIL(p_need_units::NUMERIC / grant_per_unit);

  SELECT credits_balance
    INTO bal
  FROM public.user_credits
  WHERE user_profile_id = p_user_profile_id
  FOR UPDATE;
  IF bal IS NULL OR bal < packs_needed * cost_per_unit THEN
    RETURN FALSE;
  END IF;

  UPDATE public.user_credits
  SET credits_balance = credits_balance - (packs_needed * cost_per_unit),
      updated_at = NOW()
  WHERE user_profile_id = p_user_profile_id;

  INSERT INTO public.credit_transactions(
    user_profile_id, 
    transaction_type,
    amount, 
    reason, 
    description,
    feature_used
  )
  VALUES (
    p_user_profile_id, 
    'spend',
    -(packs_needed * cost_per_unit), 
    'auto_topup', 
    CONCAT('Top-up for ', p_feature),
    p_feature
  );

  IF p_feature = 'wardrobe_items_anlyzed' THEN
    UPDATE public.limits
    SET wardrobe_items_anlyzed = wardrobe_items_anlyzed + (packs_needed * grant_per_unit),
        wardrobe_items_anlyzed_updated_at = NOW(),
        updated_at = NOW()
    WHERE user_profile_id = p_user_profile_id;
  ELSIF p_feature = 'ai_requests' THEN
    UPDATE public.limits
    SET ai_requests = ai_requests + (packs_needed * grant_per_unit),
        ai_requests_updated_at = NOW(),
        updated_at = NOW()
    WHERE user_profile_id = p_user_profile_id;
  ELSE
    UPDATE public.limits
    SET vton_used = vton_used + (packs_needed * grant_per_unit),
        vton_used_updated_at = NOW(),
        updated_at = NOW()
    WHERE user_profile_id = p_user_profile_id;
  END IF;

  RETURN TRUE;
END;
$function$
;

