CREATE OR REPLACE FUNCTION public.use_feature(p_user_profile_id bigint, p_feature character varying, p_count integer DEFAULT 1)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  l public.limits;
  available INTEGER := 0;
  ok BOOLEAN := FALSE;
BEGIN
  PERFORM public.assert_own_profile(p_user_profile_id);
  PERFORM public.reconcile_limits(p_user_profile_id);

  SELECT * INTO l FROM public.limits WHERE user_profile_id = p_user_profile_id FOR UPDATE;

  IF p_feature = 'wardrobe_items_anlyzed' THEN
    available := l.wardrobe_items_anlyzed;
  ELSIF p_feature = 'ai_requests' THEN
    available := l.ai_requests;
  ELSIF p_feature = 'ideas_viewed' THEN
    available := l.ideas_viewed;
  ELSIF p_feature = 'outfits_saved' THEN
    available := l.outfits_saved;
  ELSIF p_feature = 'vton_used' THEN
    available := l.vton_used;
  ELSE
    RETURN FALSE;
  END IF;

  IF available >= p_count THEN
    IF p_feature = 'wardrobe_items_anlyzed' THEN
      UPDATE public.limits SET wardrobe_items_anlyzed = wardrobe_items_anlyzed - p_count,
        wardrobe_items_anlyzed_updated_at = NOW(), updated_at = NOW()
      WHERE user_profile_id = p_user_profile_id;
    ELSIF p_feature = 'ai_requests' THEN
      UPDATE public.limits SET ai_requests = ai_requests - p_count,
        ai_requests_updated_at = NOW(), updated_at = NOW()
      WHERE user_profile_id = p_user_profile_id;
    ELSIF p_feature = 'ideas_viewed' THEN
      UPDATE public.limits SET ideas_viewed = ideas_viewed - p_count,
        ideas_viewed_updated_at = NOW(), updated_at = NOW()
      WHERE user_profile_id = p_user_profile_id;
    ELSIF p_feature = 'outfits_saved' THEN
      UPDATE public.limits SET outfits_saved = outfits_saved - p_count,
        outfits_saved_updated_at = NOW(), updated_at = NOW()
      WHERE user_profile_id = p_user_profile_id;
    ELSE
      UPDATE public.limits SET vton_used = vton_used - p_count,
        vton_used_updated_at = NOW(), updated_at = NOW()
      WHERE user_profile_id = p_user_profile_id;
    END IF;
    RETURN TRUE;
  END IF;

  IF p_feature IN ('wardrobe_items_anlyzed','ai_requests','vton_used') THEN
    ok := public.top_up_from_credits(p_user_profile_id, p_feature, p_count - available);
    IF ok THEN
      RETURN public.use_feature(p_user_profile_id, p_feature, p_count);
    END IF;
  END IF;

  RETURN FALSE;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.user_anon_hash(p_user_profile_id bigint)
 RETURNS text
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  select md5(p_user_profile_id::text || ':' || coalesce(current_setting('app.anon_salt', true), 'default-salt'));
$function$
;


